Code.Terraform:
```hcl
# 为阶段中所有缓存的方法启用加密
resource "aws_api_gateway_stage" "<example_resource_name>" {
  rest_api_id   = "<example_resource_id>"
  stage_name    = "<example_resource_name>"
  deployment_id = "<example_resource_id>"

  method_settings {
    resource_path        = "/*"
    http_method          = "*"
    cache_data_encrypted = true  # 关键：静态加密缓存的响应
  }
}
```
